+        return TracedLayout {
+            layout: DiagramLayout {
+                nodes: Vec::new(),
+                clusters: Vec::new(),
+                cycle_clusters: Vec::new(),
+                edges: Vec::new(),
+                bounds: LayoutRect {
+                    x: 0.0,
+                    y: 0.0,
+                    width: 0.0,
+                    height: 0.0,
+                },
+                stats: LayoutStats::default(),
+            },
+            trace,
+        };
+    }
+
+    let tree = build_tree_layout_structure(ir);
+    push_snapshot(
+        &mut trace,
+        "tree_structure",
+        node_count,
+        ir.edges.len(),
+        0,
+        0,
+    );
+
+    let span_sizes: Vec<f32> = node_sizes
+        .iter()
+        .map(|(width, height)| {
+            if tree.horizontal_depth_axis {
+                *height
+            } else {
+                *width
+            }
+        })
+        .collect();
+
+    let mut span_memo = vec![None; node_count];
