+        .map(|span| span.unwrap_or(0.0))
+        .collect();
+
+    let mut span_centers = vec![0.0_f32; node_count];
+    let mut root_cursor = 0.0_f32;
+    for root in &tree.roots {
+        let root_span = subtree_spans[*root];
+        assign_tree_span_centers(
+            *root,
+            root_cursor,
+            &tree.children,
+            &subtree_spans,
+            spacing,
